import React, { useState } from 'react';
import { ToolLayout } from '../components/ToolLayout';

const WaterIntake = () => {
  const [weight, setWeight] = useState<string>('');
  const [exercise, setExercise] = useState<string>('');
  const [result, setResult] = useState<number | null>(null);

  const calculate = () => {
    const w = parseFloat(weight);
    const e = parseFloat(exercise) || 0;
    if (isNaN(w)) return;

    // Formula: (Weight in kg * 0.033) + (exercise minutes / 30 * 0.35)
    const base = w * 0.033;
    const activityBonus = (e / 30) * 0.35;
    setResult(parseFloat((base + activityBonus).toFixed(2)));
  };

  const faqs = [
    { question: "How much water should I drink a day?", answer: "A common rule is 8 glasses, but scientifically it depends on your weight, activity level, and climate. Our calculator uses the 33ml per kg rule plus activity adjustments." },
    { question: "Does coffee count towards hydration?", answer: "Yes, though caffeine is a mild diuretic, the water in coffee and tea still contributes to your daily total." },
    { question: "How much extra water for exercise?", answer: "For every 30 minutes of vigorous activity, you should add roughly 350-500ml of water to your baseline." }
  ];

  return (
    <ToolLayout 
      title="Daily Water Intake Calculator" 
      description="Find out exactly how many liters of water your body needs daily to stay energized and healthy based on your current weight and physical activity."
      faqs={faqs}
    >
      <div className="grid grid-cols-1 md:grid-cols-2 gap-8">
        <div className="space-y-6">
          <div>
            <label className="block text-sm font-semibold text-slate-700 mb-2">Weight (kg)</label>
            <input 
              type="number" 
              value={weight} 
              onChange={(e) => setWeight(e.target.value)}
              className="w-full px-4 py-3 rounded-xl border border-slate-200 focus:ring-2 focus:ring-blue-500 outline-none transition-all"
              placeholder="e.g., 70"
            />
          </div>
          <div>
            <label className="block text-sm font-semibold text-slate-700 mb-2">Daily Exercise (minutes)</label>
            <input 
              type="number" 
              value={exercise} 
              onChange={(e) => setExercise(e.target.value)}
              className="w-full px-4 py-3 rounded-xl border border-slate-200 focus:ring-2 focus:ring-blue-500 outline-none transition-all"
              placeholder="e.g., 45"
            />
          </div>
          <button 
            onClick={calculate}
            className="w-full bg-blue-600 hover:bg-blue-700 text-white font-bold py-4 rounded-xl shadow-lg transition-all"
          >
            Calculate Intake
          </button>
        </div>

        <div className="flex flex-col items-center justify-center p-8 bg-slate-50 rounded-2xl border border-slate-100">
          {result !== null ? (
            <div className="text-center animate-in fade-in slide-in-from-bottom-4 duration-500">
              <p className="text-slate-500 uppercase tracking-widest text-xs font-bold mb-2">Recommended Daily Goal</p>
              <div className="text-6xl font-black text-blue-600 mb-2">
                {result} <span className="text-2xl font-bold">Liters</span>
              </div>
              <p className="text-slate-600">That's approximately {Math.round(result * 4)} large glasses of water.</p>
            </div>
          ) : (
            <div className="text-center text-slate-400">
              <i className="fas fa-droplet text-5xl mb-4 opacity-20"></i>
              <p>Enter your details to see <br />your hydration target.</p>
            </div>
          )}
        </div>
      </div>
    </ToolLayout>
  );
};

export default WaterIntake;

import React, { useState } from 'react';
import { ToolLayout } from '../components/ToolLayout';

const SmoothieCal = () => {
  const [base, setBase] = useState('water');
  const [fruitAmount, setFruitAmount] = useState<string>('');
  const [protein, setProtein] = useState(false);
  const [result, setResult] = useState<number | null>(null);

  const calculate = () => {
    let calories = 0;

    // Base calories per 250ml
    const bases: Record<string, number> = { water: 0, milk: 150, almond: 40, juice: 120 };
    calories += bases[base] || 0;

    // Fruit calories (approx 60 kcal per 100g)
    const grams = parseFloat(fruitAmount) || 0;
    calories += (grams / 100) * 60;

    // Protein scoop
    if (protein) calories += 120;

    setResult(Math.round(calories));
  };

  const faqs = [
    { question: "How many calories are in a typical smoothie?", answer: "A fruit-based smoothie typically ranges from 200 to 500 calories depending on whether you use water, milk, or juice as a base." },
    { question: "Are smoothies good for weight loss?", answer: "Yes, if they are high in fiber and protein, which helps keep you full. However, watch out for added sugars and high-calorie bases like full-cream milk." }
  ];

  return (
    <ToolLayout 
      title="Smoothie Calories Calculator" 
      description="Calculate the total caloric value of your homemade smoothies. Select your base, fruits, and add-ins to maintain your diet tracking accuracy."
      faqs={faqs}
    >
      <div className="grid grid-cols-1 md:grid-cols-2 gap-8">
        <div className="space-y-6">
          <div>
            <label className="block text-sm font-semibold text-slate-700 mb-2">Liquid Base (250ml)</label>
            <select 
              value={base} 
              onChange={(e) => setBase(e.target.value)}
              className="w-full px-4 py-3 rounded-xl border border-slate-200 focus:ring-2 focus:ring-blue-500 outline-none"
            >
              <option value="water">Water (0 kcal)</option>
              <option value="milk">Whole Milk (150 kcal)</option>
              <option value="almond">Almond Milk (40 kcal)</option>
              <option value="juice">Orange Juice (120 kcal)</option>
            </select>
          </div>
          <div>
            <label className="block text-sm font-semibold text-slate-700 mb-2">Total Fruit (grams)</label>
            <input 
              type="number" 
              value={fruitAmount} 
              onChange={(e) => setFruitAmount(e.target.value)}
              className="w-full px-4 py-3 rounded-xl border border-slate-200 focus:ring-2 focus:ring-blue-500 outline-none"
              placeholder="e.g., 200"
            />
          </div>
          <div className="flex items-center gap-3 p-4 bg-slate-50 rounded-xl">
            <input 
              type="checkbox" 
              checked={protein} 
              onChange={(e) => setProtein(e.target.checked)}
              className="w-5 h-5 accent-blue-600"
            />
            <label className="text-slate-700 font-medium">Add Protein Scoop (+120 kcal)</label>
          </div>
          <button 
            onClick={calculate}
            className="w-full bg-blue-600 hover:bg-blue-700 text-white font-bold py-4 rounded-xl shadow-lg transition-all"
          >
            Calculate Calories
          </button>
        </div>

        <div className="flex flex-col items-center justify-center p-8 bg-slate-50 rounded-2xl border border-slate-100">
          {result !== null ? (
            <div className="text-center">
              <p className="text-slate-500 uppercase tracking-widest text-xs font-bold mb-2">Estimated Total</p>
              <div className="text-6xl font-black text-orange-600 mb-2">
                {result} <span className="text-2xl font-bold">kcal</span>
              </div>
              <p className="text-slate-600">Great job! This is roughly 15-20% of a standard daily caloric intake.</p>
            </div>
          ) : (
            <div className="text-center text-slate-400">
              <i className="fas fa-blender text-5xl mb-4 opacity-20"></i>
              <p>Build your smoothie to calculate <br />its nutritional density.</p>
            </div>
          )}
        </div>
      </div>
    </ToolLayout>
  );
};

export default SmoothieCal;

import React, { useState } from 'react';
