const ProteinShake = () => {
  const [weight, setWeight] = useState<string>('');
  const [goal, setGoal] = useState('maintenance');
  const [result, setResult] = useState<number | null>(null);

  const calculate = () => {
    const w = parseFloat(weight);
    if (isNaN(w)) return;

    // Protein factors per kg: maintenance=1.2, building=1.8, cutting=1.5
    const factors: Record<string, number> = { maintenance: 1.2, muscle: 1.8, cutting: 1.5 };
    const dailyTotal = w * factors[goal];

    // Recommended shake size (30% of daily total)
    setResult(Math.round(dailyTotal * 0.3));
  };

  const faqs = [
    { question: "How much protein can the body absorb at once?", answer: "Most research suggests the body can efficiently process between 20-30g of protein per meal for muscle synthesis." },
    { question: "When is the best time for a protein shake?", answer: "While the 'anabolic window' is broad, consuming protein within 2 hours of a workout is ideal for recovery." }
  ];

  return (
    <ToolLayout 
      title="Protein Shake Calculator" 
      description="Determine the ideal protein content for your post-workout shake based on your weight and fitness objective."
