import React, { useState } from 'react';
import { ToolLayout } from '../components/ToolLayout';

const BMICalculator = () => {
  const [weight, setWeight] = useState<string>('');
  const [height, setHeight] = useState<string>('');
  const [bmi, setBmi] = useState<number | null>(null);

  const calculate = () => {
    const w = parseFloat(weight);
    const h = parseFloat(height) / 100; // cm to m
    if (isNaN(w) || isNaN(h) || h === 0) return;

    setBmi(parseFloat((w / (h * h)).toFixed(1)));
  };

  const getStatus = (val: number) => {
    if (val < 18.5) return { text: "Underweight", color: "text-blue-500" };
    if (val < 25) return { text: "Normal weight", color: "text-green-500" };
    if (val < 30) return { text: "Overweight", color: "text-orange-500" };
    return { text: "Obese", color: "text-red-500" };
  };

  return (
    <ToolLayout 
      title="BMI Calculator" 
      description="Quickly calculate your Body Mass Index (BMI). Knowing your BMI helps you understand your hydration and liquid nutrition needs more effectively."
      faqs={[]}
    >
      <div className="grid grid-cols-1 md:grid-cols-2 gap-8">
        <div className="space-y-6">
          <div>
            <label className="block text-sm font-semibold text-slate-700 mb-2">Weight (kg)</label>
            <input 
              type="number" 
              value={weight} 
              onChange={(e) => setWeight(e.target.value)}
              className="w-full px-4 py-3 rounded-xl border border-slate-200 focus:ring-2 focus:ring-blue-500 outline-none"
              placeholder="e.g., 75"
            />
          </div>
          <div>
            <label className="block text-sm font-semibold text-slate-700 mb-2">Height (cm)</label>
            <input 
              type="number" 
              value={height} 
              onChange={(e) => setHeight(e.target.value)}
              className="w-full px-4 py-3 rounded-xl border border-slate-200 focus:ring-2 focus:ring-blue-500 outline-none"
              placeholder="e.g., 175"
            />
          </div>
          <button 
            onClick={calculate}
            className="w-full bg-green-600 hover:bg-green-700 text-white font-bold py-4 rounded-xl shadow-lg transition-all"
          >
            Calculate BMI
          </button>
        </div>

        <div className="flex flex-col items-center justify-center p-8 bg-slate-50 rounded-2xl border border-slate-100">
          {bmi !== null ? (
            <div className="text-center">
              <p className="text-slate-500 uppercase tracking-widest text-xs font-bold mb-2">Your Result</p>
              <div className="text-7xl font-black text-slate-900 mb-2">
                {bmi}
              </div>
              <p className={`text-xl font-bold ${getStatus(bmi).color}`}>
                {getStatus(bmi).text}
              </p>
            </div>
          ) : (
            <div className="text-center text-slate-400">
              <i className="fas fa-heart-pulse text-5xl mb-4 opacity-20"></i>
              <p>Enter measurements to check <br />your BMI status.</p>
            </div>
          )}
        </div>
      </div>
    </ToolLayout>
  );
};

export default BMICalculator;

