import React, { useState } from 'react';
import { ToolLayout } from '../components/ToolLayout';

const FRUIT_DATA: Record<string, { name: string; sugarPer100ml: number; icon: string }> = {
  apple: { name: 'Apple', sugarPer100ml: 10.4, icon: 'fa-apple-whole' },
  orange: { name: 'Orange', sugarPer100ml: 8.4, icon: 'fa-citrus' },
  carrot: { name: 'Carrot', sugarPer100ml: 4.7, icon: 'fa-carrot' },
  beetroot: { name: 'Beetroot', sugarPer100ml: 6.8, icon: 'fa-leaf' },
  grape: { name: 'Grape', sugarPer100ml: 15.5, icon: 'fa-grapes' },
  pomegranate: { name: 'Pomegranate', sugarPer100ml: 12.6, icon: 'fa-circle' },
  lemon: { name: 'Lemon/Lime', sugarPer100ml: 2.5, icon: 'fa-lemon' },
  celery: { name: 'Celery', sugarPer100ml: 1.8, icon: 'fa-seedling' },
};

const JuiceSugar = () => {
  const [fruitType, setFruitType] = useState('orange');
  const [volume, setVolume] = useState<string>('250');
  const [result, setResult] = useState<{ grams: number; teaspoons: number } | null>(null);

  const calculate = () => {
    const vol = parseFloat(volume);
    const fruit = FRUIT_DATA[fruitType];
    if (isNaN(vol) || !fruit) return;

    const grams = (vol / 100) * fruit.sugarPer100ml;
    const teaspoons = grams / 4.2; // Standard approx: 1 tsp = 4.2g sugar

    setResult({
      grams: parseFloat(grams.toFixed(1)),
      teaspoons: parseFloat(teaspoons.toFixed(1)),
    });
  };

  const faqs = [
    { 
      question: "Is the sugar in fruit juice healthy?", 
      answer: "While fruit juice contains natural fructose, vitamins, and antioxidants, it lacks the fiber found in whole fruit. This causes sugar to be absorbed faster, which can spike blood glucose levels." 
    },
    { 
      question: "How much juice sugar is too much?", 
      answer: "The WHO recommends limiting 'free sugars' to less than 10% of total energy intake. For an average adult, that's about 50g. A large glass of grape juice could contain nearly half of that." 
    },
    { 
      question: "What is a low-sugar juice alternative?", 
      answer: "Vegetable-based juices like celery, cucumber, or leafy greens are significantly lower in sugar than fruit-based juices while still providing high micronutrient density." 
    }
  ];

  return (
    <ToolLayout 
      title="Juice Sugar Calculator" 
      description="Estimate the natural sugar content in your fresh-pressed or store-bought juices. Compare sugar levels across different fruit and vegetable bases."
      faqs={faqs}
    >
      <div className="grid grid-cols-1 md:grid-cols-2 gap-8">
        <div className="space-y-6">
          <div>
            <label className="block text-sm font-semibold text-slate-700 mb-2">Select Fruit/Veg Base</label>
            <div className="grid grid-cols-4 gap-2">
              {Object.entries(FRUIT_DATA).map(([key, data]) => (
                <button
                  key={key}
                  onClick={() => setFruitType(key)}
                  className={`flex flex-col items-center justify-center p-3 rounded-xl border transition-all ${
                    fruitType === key 
                      ? 'border-orange-500 bg-orange-50 text-orange-700 ring-2 ring-orange-200' 
                      : 'border-slate-200 hover:border-slate-300 text-slate-500'
                  }`}
                >
                  <i className={`fas ${data.icon} text-lg mb-1`}></i>
                  <span className="text-[10px] font-bold uppercase truncate w-full text-center">{data.name}</span>
                </button>
              ))}
            </div>
          </div>

          <div>
            <label className="block text-sm font-semibold text-slate-700 mb-2">Volume (ml)</label>
            <input 
              type="number" 
              value={volume} 
              onChange={(e) => setVolume(e.target.value)}
              className="w-full px-4 py-3 rounded-xl border border-slate-200 focus:ring-2 focus:ring-orange-500 outline-none transition-all"
              placeholder="e.g., 250"
            />
          </div>

          <button 
            onClick={calculate}
            className="w-full bg-orange-600 hover:bg-orange-700 text-white font-bold py-4 rounded-xl shadow-lg transition-all"
          >
            Estimate Sugar Content
          </button>
        </div>

        <div className="flex flex-col items-center justify-center p-8 bg-slate-50 rounded-2xl border border-slate-100">
          {result !== null ? (
            <div className="text-center animate-in fade-in slide-in-from-bottom-4 duration-500">
              <p className="text-slate-500 uppercase tracking-widest text-xs font-bold mb-2">Estimated Natural Sugar</p>
              <div className="text-6xl font-black text-orange-600 mb-2">
                {result.grams} <span className="text-2xl font-bold">g</span>
              </div>
              <div className="flex items-center justify-center gap-2 text-slate-600 font-medium bg-white px-4 py-2 rounded-full shadow-sm border border-slate-100">
                <i className="fas fa-spoon text-orange-400"></i>
                <span>Approx. {result.teaspoons} teaspoons</span>
              </div>
              <p className="mt-4 text-sm text-slate-500 italic max-w-xs mx-auto">
                Based on average sugar content for fresh {FRUIT_DATA[fruitType].name.toLowerCase()} juice.
              </p>
            </div>
          ) : (
            <div className="text-center text-slate-400">
              <i className="fas fa-glass-water text-5xl mb-4 opacity-20"></i>
              <p>Select a fruit and volume to see <br />the estimated sugar levels.</p>
            </div>
          )}
        </div>
      </div>
    </ToolLayout>
  );
